#[test]
fn lvl_ppr_overridden_by_paragraph_ppr_opens_clean() {
    let body = r#"<w:p><w:pPr><w:numPr><w:ilvl w:val="0"/><w:numId w:val="1"/></w:numPr><w:ind w:start="1440"/></w:pPr><w:r><w:t>Indented item</w:t></w:r></w:p><w:sectPr/>"#;
    let numbering = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:numbering xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:abstractNum w:abstractNumId="3"><w:multiLevelType w:val="multilevel"/><w:lvl w:ilvl="0"><w:start w:val="1"/><w:numFmt w:val="decimal"/><w:lvlText w:val="%1."/><w:lvlJc w:val="left"/><w:pPr><w:ind w:start="720" w:hanging="360"/></w:pPr></w:lvl></w:abstractNum><w:num w:numId="1"><w:abstractNumId w:val="3"/></w:num></w:numbering>"#;
    let b = make_docx(body, &[("word/numbering.xml", numbering)]);
    assert_opens_clean(
        &b,
        "ECMA-376/ISO 29500-1 §17.9.22: a numbered paragraph supplying its own pPr override (direct ind alongside the level's pPr ind) is the spec's canonical override scenario, not an error; Word opens it without repair",
    );
}

#[test]
fn lvl_child_sequence_order_opens_clean() {
    let body = r#"<w:p><w:pPr><w:pStyle w:val="NumLvl"/></w:pPr><w:r><w:t>Body</w:t></w:r></w:p><w:sectPr/>"#;
    let styles = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:styles xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:style w:type="paragraph" w:styleId="NumLvl"><w:name w:val="Num Lvl"/><w:pPr><w:numPr><w:numId w:val="0"/></w:numPr></w:pPr></w:style></w:styles>"#;
    let numbering = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><w:numbering xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:abstractNum w:abstractNumId="4"><w:multiLevelType w:val="multilevel"/><w:lvl w:ilvl="0"><w:start w:val="1"/><w:numFmt w:val="decimal"/><w:lvlText w:val="%1."/><w:pStyle w:val="NumLvl"/><w:pPr><w:ind w:start="720" w:hanging="360"/></w:pPr><w:rPr><w:b/><w:sz w:val="32"/></w:rPr></w:lvl></w:abstractNum><w:num w:numId="5"><w:abstractNumId w:val="4"/></w:num></w:numbering>"#;
    let b = make_docx(
        body,
        &[
            ("word/styles.xml", styles),
            ("word/numbering.xml", numbering),
        ],
    );
    assert_opens_clean(
        &b,
        "ECMA-376 §A.1 (CT_Lvl) / §17.9.22-24: the CT_Lvl xsd:sequence permits pStyle, pPr, rPr in that order; a schema-valid level using all three opens without repair",
    );
    let doc = Document::parse(&b).expect("parse");
    let accepted = doc.read_accepted().expect("read_accepted").to_text();
    assert_eq!(
        accepted.trim(),
        "Body",
        "ECMA-376 §17.9.24: the lvl rPr formats only the marker glyph, so the visible body text is exactly the paragraph run, with no injected marker characters",
    );
}

